"""Measure batch scoring runtime across dataset sizes."""

from __future__ import annotations

import argparse
import json
from pathlib import Path
import time
from typing import Sequence

import numpy as np

from hallucination_lens import HallucinationScorer


class DeterministicEmbeddingModel:
    """Small deterministic embedding backend for fast local runtime comparisons."""

    def encode(self, texts: Sequence[str], normalize_embeddings: bool = True) -> np.ndarray:
        """Encode input texts into deterministic 3D vectors for repeatable benchmarks."""

        vectors: list[np.ndarray] = []
        for text in texts:
            lower = text.lower()
            vector = np.array([0.2, 0.2, 0.2], dtype=np.float32)
            if "paris" in lower or "france" in lower:
                vector = np.array([1.0, 0.0, 0.0], dtype=np.float32)
            elif "berlin" in lower or "germany" in lower:
                vector = np.array([0.0, 1.0, 0.0], dtype=np.float32)
            elif "ocean" in lower:
                vector = np.array([0.0, 0.0, 1.0], dtype=np.float32)
            vectors.append(vector)

        return np.vstack(vectors)


# Generated by GitHub Copilot
def parse_sizes(raw: str) -> list[int]:
    """Parse comma-separated sizes into sorted unique positive integers."""

    sizes = sorted({int(item.strip()) for item in raw.split(",") if item.strip()})
    if not sizes or any(item <= 0 for item in sizes):
        raise ValueError("sizes must contain positive integers")
    return sizes


# Generated by GitHub Copilot
def load_pairs(path: Path) -> list[tuple[str, str]]:
    """Load context-response pairs from a JSON array benchmark file."""

    payload = json.loads(path.read_text(encoding="utf-8"))
    if not isinstance(payload, list) or not payload:
        raise ValueError("dataset must be a non-empty JSON array")

    pairs: list[tuple[str, str]] = []
    for item in payload:
        context = str(item.get("context", "")).strip()
        response = str(item.get("response", "")).strip()
        if not context or not response:
            raise ValueError("each dataset item must include non-empty context and response")
        pairs.append((context, response))

    return pairs


# Generated by GitHub Copilot
def measure_batch_runtime_ms(
    scorer: HallucinationScorer,
    pairs: list[tuple[str, str]],
    size: int,
    repeats: int,
) -> list[float]:
    """Measure repeated batch runtime in milliseconds for a given sample size."""

    subset = pairs[:size]
    measurements: list[float] = []

    for _ in range(repeats):
        started = time.perf_counter()
        _ = scorer.batch_faithfulness_scores(subset)
        elapsed_ms = (time.perf_counter() - started) * 1000.0
        measurements.append(elapsed_ms)

    return measurements


# Generated by GitHub Copilot
def main() -> None:
    """Run runtime benchmark and print markdown table plus JSON summary."""

    parser = argparse.ArgumentParser(description="Benchmark hallucination-lens runtime by dataset size")
    parser.add_argument(
        "--dataset",
        default="benchmarks/starter_dataset.json",
        help="Path to benchmark JSON dataset",
    )
    parser.add_argument(
        "--sizes",
        default="2,5,10",
        help="Comma-separated subset sizes to benchmark",
    )
    parser.add_argument(
        "--repeats",
        type=int,
        default=5,
        help="Number of repeated runs per size",
    )
    parser.add_argument(
        "--threshold",
        type=float,
        default=0.6,
        help="Faithfulness threshold to use during benchmark",
    )
    args = parser.parse_args()

    if args.repeats <= 0:
        raise ValueError("repeats must be positive")

    sizes = parse_sizes(args.sizes)
    pairs = load_pairs(Path(args.dataset))

    scorer = HallucinationScorer(
        threshold=args.threshold,
        model_name="deterministic-benchmark",
        model=DeterministicEmbeddingModel(),
    )

    valid_sizes = [item for item in sizes if item <= len(pairs)]
    if not valid_sizes:
        raise ValueError("no benchmark size is less than or equal to dataset length")

    rows: list[dict[str, float | int]] = []
    for size in valid_sizes:
        samples = measure_batch_runtime_ms(
            scorer=scorer,
            pairs=pairs,
            size=size,
            repeats=args.repeats,
        )
        rows.append(
            {
                "dataset_size": size,
                "mean_ms": round(float(np.mean(samples)), 4),
                "p95_ms": round(float(np.percentile(samples, 95)), 4),
                "max_ms": round(float(np.max(samples)), 4),
            }
        )

    print("| Dataset size | Mean runtime (ms) | P95 (ms) | Max (ms) |")
    print("| ---: | ---: | ---: | ---: |")
    for row in rows:
        print(
            f"| {row['dataset_size']} | {row['mean_ms']} | {row['p95_ms']} | {row['max_ms']} |"
        )

    print("\nJSON summary:")
    print(json.dumps(rows, indent=2))


if __name__ == "__main__":
    main()
